function TrainerDetails({ trainer }) {
  if (!trainer) {
    return <div className="card trainer-details">No trainer selected.</div>;
  }

  return (
    <div className="card trainer-details">
      <h2>{trainer.name}</h2>
      <p><strong>Specialty:</strong> {trainer.specialty}</p>
      <p><strong>Experience:</strong> {trainer.experience}</p>
      <p><strong>Bio:</strong> {trainer.bio}</p>
    </div>
  );
}

export default TrainerDetails;
